import React, { useState, useEffect, useCallback } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import {
  Container,
  Paper,
  Typography,
  Box,
  Grid,
  TextField,
  Button,
  Stepper,
  Step,
  StepLabel,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Chip,
  IconButton,
  Alert,
  CircularProgress,
  Divider,
  List,
  ListItem,
  ListItemText,
  ListItemIcon,
  LinearProgress,
  Tooltip,
  Snackbar,
} from '@mui/material';
import {
  Work as WorkIcon,
  Person as PersonIcon,
  Email as EmailIcon,
  Phone as PhoneIcon,
  LocationOn as LocationIcon,
  School as SchoolIcon,
  Business as BusinessIcon,
  Description as DescriptionIcon,
  Add as AddIcon,
  Delete as DeleteIcon,
  CloudUpload as UploadIcon,
  Save as SaveIcon,
  CheckCircle as CheckCircleIcon,
  Error as ErrorIcon,
} from '@mui/icons-material';
import { useForm, Controller, useFieldArray } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import * as z from 'zod';
import axios from 'axios';

interface JobDetails {
  id: string;
  title: string;
  company: string;
  department: string;
  location: string;
  type: string;
}

const validationSchema = z.object({
  personalInfo: z.object({
    firstName: z.string().min(1, 'First name is required'),
    lastName: z.string().min(1, 'Last name is required'),
    email: z.string().email('Invalid email').min(1, 'Email is required'),
    phone: z.string().min(1, 'Phone number is required'),
    location: z.string().min(1, 'Location is required'),
  }),
  education: z.array(z.object({
    degree: z.string().min(1, 'Degree is required'),
    institution: z.string().min(1, 'Institution is required'),
    field: z.string().min(1, 'Field of study is required'),
    startDate: z.string().min(1, 'Start date is required'),
    endDate: z.string().min(1, 'End date is required'),
    gpa: z.string().optional(),
  })),
  experience: z.array(z.object({
    title: z.string().min(1, 'Job title is required'),
    company: z.string().min(1, 'Company is required'),
    location: z.string().min(1, 'Location is required'),
    startDate: z.string().min(1, 'Start date is required'),
    endDate: z.string().min(1, 'End date is required'),
    description: z.string().min(1, 'Description is required'),
  })),
  skills: z.array(z.string()).min(1, 'At least one skill is required'),
  resume: z.instanceof(File).nullable(),
  coverLetter: z.string().min(1, 'Cover letter is required'),
  availability: z.object({
    startDate: z.string().min(1, 'Start date is required'),
    noticePeriod: z.string().min(1, 'Notice period is required'),
  }),
});

type FormData = z.infer<typeof validationSchema>;

const ApplicationForm: React.FC = () => {
  const { jobId } = useParams<{ jobId: string }>();
  const navigate = useNavigate();
  const [activeStep, setActiveStep] = useState(0);
  const [job, setJob] = useState<JobDetails | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [saveStatus, setSaveStatus] = useState<'saved' | 'saving' | 'error' | null>(null);
  const [autoSaveTimeout, setAutoSaveTimeout] = useState<NodeJS.Timeout | null>(null);

  const {
    control,
    handleSubmit,
    formState: { errors, isDirty },
    watch,
    setValue,
    getValues,
  } = useForm<FormData>({
    resolver: zodResolver(validationSchema),
    defaultValues: {
      personalInfo: {
        firstName: '',
        lastName: '',
        email: '',
        phone: '',
        location: '',
      },
      education: [{
        degree: '',
        institution: '',
        field: '',
        startDate: '',
        endDate: '',
        gpa: '',
      }],
      experience: [{
        title: '',
        company: '',
        location: '',
        startDate: '',
        endDate: '',
        description: '',
      }],
      skills: [],
      resume: null,
      coverLetter: '',
      availability: {
        startDate: '',
        noticePeriod: '',
      },
    },
  });

  const { fields: educationFields, append: appendEducation, remove: removeEducation } = useFieldArray({
    control,
    name: 'education',
  });

  const { fields: experienceFields, append: appendExperience, remove: removeExperience } = useFieldArray({
    control,
    name: 'experience',
  });

  const autoSave = useCallback(() => {
    if (autoSaveTimeout) {
      clearTimeout(autoSaveTimeout);
    }

    setSaveStatus('saving');
    const timeout = setTimeout(async () => {
      try {
        await axios.post(`/api/jobs/${jobId}/draft`, getValues());
        setSaveStatus('saved');
      } catch (err) {
        setSaveStatus('error');
      }
    }, 1000);

    setAutoSaveTimeout(timeout);
  }, [getValues, jobId, autoSaveTimeout]);

  useEffect(() => {
    const fetchJobDetails = async () => {
      try {
        const response = await axios.get(`/api/jobs/${jobId}`);
        setJob(response.data);
      } catch (err) {
        setError('Failed to load job details');
      } finally {
        setLoading(false);
      }
    };

    fetchJobDetails();
  }, [jobId]);

  useEffect(() => {
    if (isDirty) {
      autoSave();
    }
    return () => {
      if (autoSaveTimeout) {
        clearTimeout(autoSaveTimeout);
      }
    };
  }, [isDirty, autoSave]);

  const onSubmit = async (data: FormData) => {
    try {
      const formDataToSend = new FormData();
      Object.entries(data).forEach(([key, value]) => {
        if (key === 'resume' && value) {
          formDataToSend.append('resume', value);
        } else {
          formDataToSend.append(key, JSON.stringify(value));
        }
      });

      await axios.post(`/api/jobs/${jobId}/apply`, formDataToSend, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
      });

      navigate('/dashboard');
    } catch (err) {
      setError('Failed to submit application');
    }
  };

  const handleNext = () => {
    const currentStepFields = getStepFields(activeStep);
    const hasErrors = currentStepFields.some(field => errors[field]);
    
    if (!hasErrors) {
      setActiveStep((prevStep) => prevStep + 1);
    }
  };

  const handleBack = () => {
    setActiveStep((prevStep) => prevStep - 1);
  };

  const getStepFields = (step: number): string[] => {
    switch (step) {
      case 0:
        return ['personalInfo'];
      case 1:
        return ['education', 'experience'];
      case 2:
        return ['skills', 'resume', 'coverLetter'];
      case 3:
        return ['availability'];
      default:
        return [];
    }
  };

  const calculateProgress = () => {
    const values = getValues();
    const totalFields = Object.keys(values).length;
    const filledFields = Object.entries(values).filter(([_, value]) => {
      if (Array.isArray(value)) return value.length > 0;
      if (typeof value === 'object' && value !== null) {
        return Object.values(value).some(v => v !== '');
      }
      return value !== '';
    }).length;

    return (filledFields / totalFields) * 100;
  };

  if (loading) {
    return (
      <Box display="flex" justifyContent="center" alignItems="center" minHeight="80vh">
        <CircularProgress />
      </Box>
    );
  }

  if (error || !job) {
    return (
      <Container maxWidth="md" sx={{ py: 4 }}>
        <Alert severity="error">{error || 'Job not found'}</Alert>
      </Container>
    );
  }

  const steps = [
    'Personal Information',
    'Education & Experience',
    'Skills & Documents',
    'Review & Submit'
  ];

  return (
    <Container maxWidth="md" sx={{ py: 4 }}>
      <Paper elevation={3} sx={{ p: 4, borderRadius: 2 }}>
        <Box mb={4}>
          <Typography variant="h4" gutterBottom>
            Apply for {job.title}
          </Typography>
          <Typography variant="subtitle1" color="text.secondary">
            {job.company} • {job.location}
          </Typography>
        </Box>

        <Box display="flex" alignItems="center" mb={2}>
          <LinearProgress
            variant="determinate"
            value={calculateProgress()}
            sx={{ flexGrow: 1, mr: 2 }}
          />
          <Typography variant="body2" color="text.secondary">
            {Math.round(calculateProgress())}% Complete
          </Typography>
        </Box>

        <Box display="flex" alignItems="center" mb={4}>
          {saveStatus === 'saving' && (
            <Typography variant="body2" color="text.secondary">
              <CircularProgress size={16} sx={{ mr: 1 }} />
              Saving...
            </Typography>
          )}
          {saveStatus === 'saved' && (
            <Typography variant="body2" color="success.main">
              <CheckCircleIcon fontSize="small" sx={{ mr: 1 }} />
              Draft saved
            </Typography>
          )}
          {saveStatus === 'error' && (
            <Typography variant="body2" color="error.main">
              <ErrorIcon fontSize="small" sx={{ mr: 1 }} />
              Failed to save draft
            </Typography>
          )}
        </Box>

        <Stepper activeStep={activeStep} sx={{ mb: 4 }}>
          {steps.map((label) => (
            <Step key={label}>
              <StepLabel>{label}</StepLabel>
            </Step>
          ))}
        </Stepper>

        <form onSubmit={handleSubmit(onSubmit)}>
          {activeStep === 0 && (
            <Box>
              <Typography variant="h6" gutterBottom>
                Personal Information
              </Typography>
              <Grid container spacing={3}>
                <Grid item xs={12} sm={6}>
                  <Controller
                    name="personalInfo.firstName"
                    control={control}
                    render={({ field }) => (
                      <TextField
                        {...field}
                        fullWidth
                        label="First Name"
                        error={!!errors.personalInfo?.firstName}
                        helperText={errors.personalInfo?.firstName?.message}
                      />
                    )}
                  />
                </Grid>
                <Grid item xs={12} sm={6}>
                  <Controller
                    name="personalInfo.lastName"
                    control={control}
                    render={({ field }) => (
                      <TextField
                        {...field}
                        fullWidth
                        label="Last Name"
                        error={!!errors.personalInfo?.lastName}
                        helperText={errors.personalInfo?.lastName?.message}
                      />
                    )}
                  />
                </Grid>
                <Grid item xs={12}>
                  <Controller
                    name="personalInfo.email"
                    control={control}
                    render={({ field }) => (
                      <TextField
                        {...field}
                        fullWidth
                        label="Email"
                        type="email"
                        error={!!errors.personalInfo?.email}
                        helperText={errors.personalInfo?.email?.message}
                      />
                    )}
                  />
                </Grid>
                <Grid item xs={12} sm={6}>
                  <Controller
                    name="personalInfo.phone"
                    control={control}
                    render={({ field }) => (
                      <TextField
                        {...field}
                        fullWidth
                        label="Phone"
                        error={!!errors.personalInfo?.phone}
                        helperText={errors.personalInfo?.phone?.message}
                      />
                    )}
                  />
                </Grid>
                <Grid item xs={12} sm={6}>
                  <Controller
                    name="personalInfo.location"
                    control={control}
                    render={({ field }) => (
                      <TextField
                        {...field}
                        fullWidth
                        label="Location"
                        error={!!errors.personalInfo?.location}
                        helperText={errors.personalInfo?.location?.message}
                      />
                    )}
                  />
                </Grid>
              </Grid>
            </Box>
          )}

          {activeStep === 1 && (
            <Box>
              <Typography variant="h6" gutterBottom>
                Education
              </Typography>
              {educationFields.map((field, index) => (
                <Box key={field.id} mb={3}>
                  <Grid container spacing={2}>
                    <Grid item xs={12} sm={6}>
                      <Controller
                        name={`education.${index}.degree`}
                        control={control}
                        render={({ field }) => (
                          <TextField
                            {...field}
                            fullWidth
                            label="Degree"
                            error={!!errors.education?.[index]?.degree}
                            helperText={errors.education?.[index]?.degree?.message}
                          />
                        )}
                      />
                    </Grid>
                    <Grid item xs={12} sm={6}>
                      <Controller
                        name={`education.${index}.institution`}
                        control={control}
                        render={({ field }) => (
                          <TextField
                            {...field}
                            fullWidth
                            label="Institution"
                            error={!!errors.education?.[index]?.institution}
                            helperText={errors.education?.[index]?.institution?.message}
                          />
                        )}
                      />
                    </Grid>
                    <Grid item xs={12} sm={6}>
                      <Controller
                        name={`education.${index}.field`}
                        control={control}
                        render={({ field }) => (
                          <TextField
                            {...field}
                            fullWidth
                            label="Field of Study"
                            error={!!errors.education?.[index]?.field}
                            helperText={errors.education?.[index]?.field?.message}
                          />
                        )}
                      />
                    </Grid>
                    <Grid item xs={12} sm={3}>
                      <Controller
                        name={`education.${index}.startDate`}
                        control={control}
                        render={({ field }) => (
                          <TextField
                            {...field}
                            fullWidth
                            label="Start Date"
                            type="date"
                            error={!!errors.education?.[index]?.startDate}
                            helperText={errors.education?.[index]?.startDate?.message}
                            InputLabelProps={{ shrink: true }}
                          />
                        )}
                      />
                    </Grid>
                    <Grid item xs={12} sm={3}>
                      <Controller
                        name={`education.${index}.endDate`}
                        control={control}
                        render={({ field }) => (
                          <TextField
                            {...field}
                            fullWidth
                            label="End Date"
                            type="date"
                            error={!!errors.education?.[index]?.endDate}
                            helperText={errors.education?.[index]?.endDate?.message}
                            InputLabelProps={{ shrink: true }}
                          />
                        )}
                      />
                    </Grid>
                    <Grid item xs={12} sm={6}>
                      <Controller
                        name={`education.${index}.gpa`}
                        control={control}
                        render={({ field }) => (
                          <TextField
                            {...field}
                            fullWidth
                            label="GPA (Optional)"
                          />
                        )}
                      />
                    </Grid>
                  </Grid>
                  <Box display="flex" justifyContent="flex-end" mt={1}>
                    <IconButton onClick={() => removeEducation(index)} color="error">
                      <DeleteIcon />
                    </IconButton>
                  </Box>
                </Box>
              ))}
              <Button
                startIcon={<AddIcon />}
                onClick={() => appendEducation({
                  degree: '',
                  institution: '',
                  field: '',
                  startDate: '',
                  endDate: '',
                  gpa: '',
                })}
                sx={{ mb: 4 }}
              >
                Add Education
              </Button>

              <Typography variant="h6" gutterBottom>
                Experience
              </Typography>
              {experienceFields.map((field, index) => (
                <Box key={field.id} mb={3}>
                  <Grid container spacing={2}>
                    <Grid item xs={12} sm={6}>
                      <Controller
                        name={`experience.${index}.title`}
                        control={control}
                        render={({ field }) => (
                          <TextField
                            {...field}
                            fullWidth
                            label="Job Title"
                            error={!!errors.experience?.[index]?.title}
                            helperText={errors.experience?.[index]?.title?.message}
                          />
                        )}
                      />
                    </Grid>
                    <Grid item xs={12} sm={6}>
                      <Controller
                        name={`experience.${index}.company`}
                        control={control}
                        render={({ field }) => (
                          <TextField
                            {...field}
                            fullWidth
                            label="Company"
                            error={!!errors.experience?.[index]?.company}
                            helperText={errors.experience?.[index]?.company?.message}
                          />
                        )}
                      />
                    </Grid>
                    <Grid item xs={12} sm={6}>
                      <Controller
                        name={`experience.${index}.location`}
                        control={control}
                        render={({ field }) => (
                          <TextField
                            {...field}
                            fullWidth
                            label="Location"
                            error={!!errors.experience?.[index]?.location}
                            helperText={errors.experience?.[index]?.location?.message}
                          />
                        )}
                      />
                    </Grid>
                    <Grid item xs={12} sm={3}>
                      <Controller
                        name={`experience.${index}.startDate`}
                        control={control}
                        render={({ field }) => (
                          <TextField
                            {...field}
                            fullWidth
                            label="Start Date"
                            type="date"
                            error={!!errors.experience?.[index]?.startDate}
                            helperText={errors.experience?.[index]?.startDate?.message}
                            InputLabelProps={{ shrink: true }}
                          />
                        )}
                      />
                    </Grid>
                    <Grid item xs={12} sm={3}>
                      <Controller
                        name={`experience.${index}.endDate`}
                        control={control}
                        render={({ field }) => (
                          <TextField
                            {...field}
                            fullWidth
                            label="End Date"
                            type="date"
                            error={!!errors.experience?.[index]?.endDate}
                            helperText={errors.experience?.[index]?.endDate?.message}
                            InputLabelProps={{ shrink: true }}
                          />
                        )}
                      />
                    </Grid>
                    <Grid item xs={12}>
                      <Controller
                        name={`experience.${index}.description`}
                        control={control}
                        render={({ field }) => (
                          <TextField
                            {...field}
                            fullWidth
                            label="Description"
                            multiline
                            rows={4}
                            error={!!errors.experience?.[index]?.description}
                            helperText={errors.experience?.[index]?.description?.message}
                          />
                        )}
                      />
                    </Grid>
                  </Grid>
                  <Box display="flex" justifyContent="flex-end" mt={1}>
                    <IconButton onClick={() => removeExperience(index)} color="error">
                      <DeleteIcon />
                    </IconButton>
                  </Box>
                </Box>
              ))}
              <Button
                startIcon={<AddIcon />}
                onClick={() => appendExperience({
                  title: '',
                  company: '',
                  location: '',
                  startDate: '',
                  endDate: '',
                  description: '',
                })}
              >
                Add Experience
              </Button>
            </Box>
          )}

          {activeStep === 2 && (
            <Box>
              <Typography variant="h6" gutterBottom>
                Skills
              </Typography>
              <Box display="flex" gap={1} mb={3}>
                <Controller
                  name="skills"
                  control={control}
                  render={({ field }) => (
                    <TextField
                      fullWidth
                      label="Add Skill"
                      value={field.value}
                      onChange={(e) => {
                        const skill = e.target.value;
                        if (skill && !field.value.includes(skill)) {
                          field.onChange([...field.value, skill]);
                        }
                      }}
                      error={!!errors.skills}
                      helperText={errors.skills?.message}
                    />
                  )}
                />
              </Box>
              <Box display="flex" flexWrap="wrap" gap={1} mb={4}>
                {watch('skills').map((skill, index) => (
                  <Chip
                    key={index}
                    label={skill}
                    onDelete={() => {
                      const newSkills = watch('skills').filter((_, i) => i !== index);
                      setValue('skills', newSkills);
                    }}
                  />
                ))}
              </Box>

              <Typography variant="h6" gutterBottom>
                Documents
              </Typography>
              <Box
                sx={{
                  border: '2px dashed',
                  borderColor: 'grey.300',
                  borderRadius: 1,
                  p: 3,
                  textAlign: 'center',
                  cursor: 'pointer',
                  mb: 3,
                }}
                onClick={() => document.getElementById('resume-upload')?.click()}
              >
                <input
                  id="resume-upload"
                  type="file"
                  hidden
                  accept=".pdf,.doc,.docx"
                  onChange={(e) => {
                    if (e.target.files && e.target.files[0]) {
                      setValue('resume', e.target.files[0]);
                    }
                  }}
                />
                <UploadIcon sx={{ fontSize: 40, color: 'primary.main', mb: 2 }} />
                <Typography variant="body1">
                  Click to upload your resume
                </Typography>
                <Typography variant="body2" color="text.secondary">
                  Supported formats: PDF, DOC, DOCX
                </Typography>
                {watch('resume') && (
                  <Typography variant="body2" color="success.main" sx={{ mt: 1 }}>
                    Selected: {watch('resume')?.name}
                  </Typography>
                )}
              </Box>

              <Controller
                name="coverLetter"
                control={control}
                render={({ field }) => (
                  <TextField
                    {...field}
                    fullWidth
                    label="Cover Letter"
                    multiline
                    rows={6}
                    error={!!errors.coverLetter}
                    helperText={errors.coverLetter?.message}
                  />
                )}
              />
            </Box>
          )}

          {activeStep === 3 && (
            <Box>
              <Typography variant="h6" gutterBottom>
                Review Your Application
              </Typography>
              <List>
                <ListItem>
                  <ListItemIcon>
                    <PersonIcon color="primary" />
                  </ListItemIcon>
                  <ListItemText
                    primary="Personal Information"
                    secondary={`${watch('personalInfo.firstName')} ${watch('personalInfo.lastName')}`}
                  />
                </ListItem>
                <ListItem>
                  <ListItemIcon>
                    <EmailIcon color="primary" />
                  </ListItemIcon>
                  <ListItemText primary="Email" secondary={watch('personalInfo.email')} />
                </ListItem>
                <ListItem>
                  <ListItemIcon>
                    <PhoneIcon color="primary" />
                  </ListItemIcon>
                  <ListItemText primary="Phone" secondary={watch('personalInfo.phone')} />
                </ListItem>
                <ListItem>
                  <ListItemIcon>
                    <LocationIcon color="primary" />
                  </ListItemIcon>
                  <ListItemText primary="Location" secondary={watch('personalInfo.location')} />
                </ListItem>
              </List>

              <Divider sx={{ my: 2 }} />

              <Typography variant="subtitle1" gutterBottom>
                Education
              </Typography>
              {watch('education').map((edu, index) => (
                <Box key={index} mb={2}>
                  <Typography variant="body1">
                    {edu.degree} at {edu.institution}
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    {edu.field} • {edu.startDate} - {edu.endDate}
                  </Typography>
                </Box>
              ))}

              <Divider sx={{ my: 2 }} />

              <Typography variant="subtitle1" gutterBottom>
                Experience
              </Typography>
              {watch('experience').map((exp, index) => (
                <Box key={index} mb={2}>
                  <Typography variant="body1">
                    {exp.title} at {exp.company}
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    {exp.location} • {exp.startDate} - {exp.endDate}
                  </Typography>
                  <Typography variant="body2" sx={{ mt: 1 }}>
                    {exp.description}
                  </Typography>
                </Box>
              ))}

              <Divider sx={{ my: 2 }} />

              <Typography variant="subtitle1" gutterBottom>
                Skills
              </Typography>
              <Box display="flex" flexWrap="wrap" gap={1} mb={2}>
                {watch('skills').map((skill, index) => (
                  <Chip key={index} label={skill} />
                ))}
              </Box>

              <Divider sx={{ my: 2 }} />

              <Typography variant="subtitle1" gutterBottom>
                Documents
              </Typography>
              <Typography variant="body2" color="text.secondary">
                Resume: {watch('resume') ? watch('resume')?.name : 'Not uploaded'}
              </Typography>
            </Box>
          )}

          <Box display="flex" justifyContent="space-between" mt={4}>
            <Button
              disabled={activeStep === 0}
              onClick={handleBack}
            >
              Back
            </Button>
            <Button
              variant="contained"
              onClick={activeStep === steps.length - 1 ? handleSubmit(onSubmit) : handleNext}
            >
              {activeStep === steps.length - 1 ? 'Submit Application' : 'Next'}
            </Button>
          </Box>
        </form>
      </Paper>

      <Snackbar
        open={saveStatus === 'saved'}
        autoHideDuration={3000}
        onClose={() => setSaveStatus(null)}
        message="Draft saved successfully"
      />
    </Container>
  );
};

export default ApplicationForm;
